#include <bits/stdc++.h>
using namespace std;
int main(){
    string s;
    cin >> s;
    int k;
    cin >> k;
    int max_len = 0;
    int start = 0;
    unordered_map<char, int> char_count;
    int max_count = 0;
    for (int end = 0; end < s.size(); end++){
        char_count[s[end]]++;
        max_count = max(max_count, char_count[s[end]]);
        if (end - start + 1 - max_count > k){
            char_count[s[start]]--;
            start++;
        }
        max_len = max(max_len, end - start + 1);
    }
    cout << max_len;
}
